package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.AccessibleObject;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class ReflectionHelperTest {

  // Create an interface matching the RecordHelper's getAccessor method
  interface RecordHelperInterface {
    Method getAccessor(Class<?> raw, Field field);
  }

  // Dummy implementation to use instead of ReflectionHelper.RecordHelper
  static class DummyRecordHelper implements RecordHelperInterface {
    private final Method accessorMethod;

    DummyRecordHelper(Method accessorMethod) {
      this.accessorMethod = accessorMethod;
    }

    @Override
    public Method getAccessor(Class<?> raw, Field field) {
      return accessorMethod;
    }
  }

  static class DummyClass {
    public String field;
  }

  private static Field dummyField;
  private static Method dummyMethod;

  @BeforeAll
  static void setup() throws NoSuchFieldException, NoSuchMethodException {
    dummyField = DummyClass.class.getField("field");
    dummyMethod = DummyClass.class.getMethod("toString");
  }

  @Test
  void getAccessor_returnsMethodFromRecordHelper() throws Exception {
    // Access the private static final RECORD_HELPER field
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Create dummyRecordHelper instance (must be of the same type as RECORD_HELPER)
    // Use a dynamic proxy or Mockito to create a proper instance of the RecordHelper type
    Class<?> recordHelperType = recordHelperField.getType();

    Object dummyRecordHelper = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperType.getClassLoader(),
        new Class<?>[] { recordHelperType },
        (proxy, method, args) -> {
          if ("getAccessor".equals(method.getName())) {
            return dummyMethod;
          }
          throw new UnsupportedOperationException("Unexpected method: " + method.getName());
        });

    // Remove final modifier from RECORD_HELPER field
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);

    // Set the RECORD_HELPER field to dummyRecordHelper
    recordHelperField.set(null, dummyRecordHelper);

    // Call the method under test
    Method result = ReflectionHelper.getAccessor(DummyClass.class, dummyField);

    assertSame(dummyMethod, result);
  }

}
